// ============================================================
// pages/StatusPage.jsx — Application Status Tracker
// ============================================================
// Shows the current status of the merchant's application,
// a visual timeline, and any admin remarks.
// ============================================================

import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { applicationAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";
import "../styles/dashboard.css";

// Each status step in the onboarding journey
const STATUS_STEPS = [
  { key: "pending",      label: "Application Submitted",  icon: "📝" },
  { key: "under_review", label: "Under Review",            icon: "🔍" },
  { key: "approved",     label: "Approved",                icon: "✅" },
];

// Icon and color per status
const STATUS_CONFIG = {
  pending:      { icon: "⏳", label: "Pending",      color: "#D97706" },
  under_review: { icon: "🔍", label: "Under Review",  color: "#2563EB" },
  approved:     { icon: "✅", label: "Approved",      color: "#16A34A" },
  rejected:     { icon: "❌", label: "Rejected",      color: "#DC2626" },
};

function StatusPage() {
  const { logout } = useAuth();
  const [application, setApplication] = useState(null);
  const [loading, setLoading]         = useState(true);
  const [error, setError]             = useState("");

  useEffect(() => {
    applicationAPI.getStatus()
      .then((res) => setApplication(res.data))
      .catch((err) => {
        if (err.response?.status === 404) {
          setError("No application found. Please submit your application first.");
        } else {
          setError("Failed to load application status.");
        }
      })
      .finally(() => setLoading(false));
  }, []);

  const statusConfig = application ? STATUS_CONFIG[application.status] : null;
  const currentStepIndex = STATUS_STEPS.findIndex((s) => s.key === application?.status);

  return (
    <div className="dashboard-layout">
      <aside className="sidebar">
        <div className="sidebar-logo">PayOnboard</div>
        <ul className="sidebar-nav">
          <li><Link to="/dashboard">🏠 Dashboard</Link></li>
          <li><Link to="/apply">📄 Apply Now</Link></li>
          <li><Link to="/status" className="active">🔍 Track Status</Link></li>
        </ul>
        <div className="sidebar-footer">
          <button onClick={logout} style={{ background:"none", border:"none", color:"var(--color-text-secondary)", cursor:"pointer", fontSize:"0.875rem" }}>
            🚪 Logout
          </button>
        </div>
      </aside>

      <main className="main-content">
        <h1 className="page-title" style={{ marginBottom: "var(--space-xl)" }}>Application Status</h1>

        {loading && <div className="spinner" />}
        {error   && <div className="alert alert-error">{error} <Link to="/apply">Apply now →</Link></div>}

        {application && (
          <>
            {/* Big Status Icon */}
            <div className="card" style={{ textAlign: "center", marginBottom: "var(--space-xl)" }}>
              <div
                className={`status-icon ${application.status}`}
                style={{ width: 80, height: 80, fontSize: "2.5rem", lineHeight: "80px", borderRadius: "50%", margin: "0 auto var(--space-lg)" }}
              >
                {statusConfig.icon}
              </div>
              <h2 style={{ fontFamily: "var(--font-display)", fontSize: "1.5rem", color: statusConfig.color }}>
                {statusConfig.label}
              </h2>
              <p style={{ color: "var(--color-text-secondary)", marginTop: "var(--space-sm)" }}>
                Submitted on {new Date(application.submitted_at).toLocaleDateString("en-IN", {
                  day: "numeric", month: "long", year: "numeric"
                })}
              </p>
            </div>

            {/* Progress Timeline (only for non-rejected) */}
            {application.status !== "rejected" && (
              <div className="card" style={{ marginBottom: "var(--space-xl)" }}>
                <h3 style={{ fontWeight: 600, marginBottom: "var(--space-lg)" }}>Progress</h3>
                <div style={{ display: "flex", justifyContent: "space-between", position: "relative" }}>
                  {/* Connector line */}
                  <div style={{
                    position: "absolute", top: 20, left: 0, right: 0, height: 2,
                    background: "var(--color-border)", zIndex: 0
                  }} />
                  {STATUS_STEPS.map((step, i) => {
                    const isCompleted = i <= currentStepIndex;
                    return (
                      <div key={step.key} style={{ textAlign: "center", flex: 1, position: "relative", zIndex: 1 }}>
                        <div style={{
                          width: 40, height: 40,
                          borderRadius: "50%",
                          background: isCompleted ? "var(--color-primary)" : "var(--color-border)",
                          color: isCompleted ? "white" : "var(--color-text-secondary)",
                          display: "flex", alignItems: "center", justifyContent: "center",
                          margin: "0 auto var(--space-sm)",
                          fontSize: "1rem"
                        }}>
                          {isCompleted ? "✓" : step.icon}
                        </div>
                        <div style={{ fontSize: "0.8125rem", fontWeight: isCompleted ? 600 : 400, color: isCompleted ? "var(--color-primary)" : "var(--color-text-secondary)" }}>
                          {step.label}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Admin Remarks */}
            {application.remarks && (
              <div className="card">
                <h3 style={{ fontWeight: 600, marginBottom: "var(--space-sm)" }}>Admin Remarks</h3>
                <div className="alert alert-info">{application.remarks}</div>
              </div>
            )}
          </>
        )}
      </main>
    </div>
  );
}

export default StatusPage;
